import React, { useRef, useEffect, useMemo } from 'react';
import { useLanguage } from '../contexts/LanguageContext';
import { getKeyboardConfig } from '../config/keyboardLoader';

// ── Finger colours ────────────────────────────────────────────────────────────
const FINGER_COLORS = {
  lp:'#f87171', lr:'#fb923c', lm:'#eab308', li:'#4ade80',
  ri:'#34d399', rm:'#60a5fa', rr:'#a78bfa', rp:'#f472b6', th:'#94a3b8',
};

const FINGER_NAMES = {
  lp:{ en:'Left Pinky',   pu:'ਖੱਬੀ ਕਾਨੀ' },
  lr:{ en:'Left Ring',    pu:'ਖੱਬੀ ਅਨਾਮਿਕਾ' },
  lm:{ en:'Left Middle',  pu:'ਖੱਬੀ ਵਿਚਕਾਰਲੀ' },
  li:{ en:'Left Index',   pu:'ਖੱਬੀ ਤਰਜਨੀ' },
  ri:{ en:'Right Index',  pu:'ਸੱਜੀ ਤਰਜਨੀ' },
  rm:{ en:'Right Middle', pu:'ਸੱਜੀ ਵਿਚਕਾਰਲੀ' },
  rr:{ en:'Right Ring',   pu:'ਸੱਜੀ ਅਨਾਮਿਕਾ' },
  rp:{ en:'Right Pinky',  pu:'ਸੱਜੀ ਕਾਨੀ' },
  th:{ en:'Thumb',        pu:'ਅੰਗੂਠਾ' },
};

const ENGLISH_FM = {
  '`':'lp','1':'lp','q':'lp','a':'lp','z':'lp','tab':'lp','caps':'lp','sl':'lp',
  '2':'lr','w':'lr','s':'lr','x':'lr',
  '3':'lm','e':'lm','d':'lm','c':'lm',
  '4':'li','5':'li','r':'li','t':'li','f':'li','g':'li','v':'li','b':'li',
  '6':'ri','7':'ri','y':'ri','u':'ri','h':'ri','j':'ri','n':'ri','m':'ri',
  '8':'rm','i':'rm','k':'rm',',':'rm',
  '9':'rr','o':'rr','l':'rr','.':'rr',
  '0':'rp','-':'rp','=':'rp','p':'rp','[':'rp',']':'rp','\\':'rp',
  ';':'rp',"'":'rp','/':'rp','enter':'rp','bs':'rp','sr':'rp',' ':'th',
};

// Left-hand key → Right Shift (sr) | Right-hand key → Left Shift (sl)
const getShiftKey = (charFc) => charFc?.startsWith('l') ? 'sr' : 'sl';
const getShiftFc  = (charFc) => charFc?.startsWith('l') ? 'rp' : 'lp';

// ── Key dimensions — widened ──────────────────────────────────────────────────
const UNIT = 50;   // was 46, now wider
const GAP  = 3;

const WIDES = { bs:2, tab:1.5, caps:1.75, enter:2.25, sl:2.25, sr:2.75, ' ':10 };
const SPEC_LABELS = {
  bs:'⌫', tab:'Tab', caps:'Caps', enter:'↵',
  sl:'Shift', sr:'Shift', ' ':'Space',
};
const CARD_H = 42;

const kw = (id, wide) => {
  if (WIDES[id]) return WIDES[id] * UNIT + (WIDES[id] - 1) * GAP;
  if (wide)      return 1.5 * UNIT + GAP;
  return UNIT;
};

// ── Mini Hand ─────────────────────────────────────────────────────────────────
function MiniHand({ side, activeFingers }) {
  const isLeft  = side === 'left';
  const fingers = isLeft
    ? [['lp',0.62],['lr',0.82],['lm',1.0],['li',0.86],['th',0.5]]
    : [['th',0.5],['ri',0.86],['rm',1.0],['rr',0.82],['rp',0.62]];
  return (
    <div style={{ display:'flex', alignItems:'flex-end', gap:2, height:CARD_H, flexShrink:0, paddingBottom:4 }}>
      {fingers.map(([fid, ratio]) => {
        const active  = activeFingers.includes(fid);
        const color   = FINGER_COLORS[fid];
        const h       = Math.round(26 * ratio);
        const isThumb = fid === 'th';
        return (
          <div key={fid} style={{
            width: isThumb ? 7 : 9, height: h,
            borderRadius: isThumb ? '4px 4px 2px 6px' : '5px 5px 2px 2px',
            background: active ? color : '#e2e8f0',
            border: `1.5px solid ${active ? color : '#d1d5db'}`,
            boxShadow: active ? `0 0 7px ${color}cc` : 'none',
            transition: 'all 0.12s',
          }}/>
        );
      })}
    </div>
  );
}

// ── Suggestion Box ────────────────────────────────────────────────────────────
function SuggestionBox({ activeKey, physKey, charFc, needShift }) {
  if (!activeKey || !charFc) return (
    <div style={{ padding:'0 20px', display:'flex', alignItems:'center', justifyContent:'center', height:CARD_H }}>
      <span style={{ color:'#cbd5e1', fontSize:12 }}>Start typing…</span>
    </div>
  );

  const color   = FINGER_COLORS[charFc];
  const fn      = FINGER_NAMES[charFc] || { en:'', pu:'' };
  const shiftFc = needShift ? getShiftFc(charFc) : null;
  const shiftFn = shiftFc ? FINGER_NAMES[shiftFc] : null;

  const card = (highlight, extra = {}) => ({
    height: CARD_H, borderRadius: 9, flexShrink: 0,
    background: highlight ? `${color}10` : '#fff',
    border: `1.5px solid ${highlight ? color + '55' : '#e8ecf0'}`,
    boxShadow: highlight ? `0 2px 8px ${color}18` : '0 1px 3px rgba(0,0,0,0.04)',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    ...extra,
  });

  const Arrow = () => (
    <span style={{ color:'#d1d5db', fontSize:15, flexShrink:0, width:14, textAlign:'center', lineHeight:1 }}>›</span>
  );

  return (
    <div style={{ display:'flex', alignItems:'center', gap:3, padding:'0 14px', flexShrink:0 }}>

      {/* TYPE */}
      <div style={card(true, { padding:'0 16px' })}>
        <span style={{
          fontFamily:"'Raavi','Noto Sans Gurmukhi',sans-serif",
          fontSize:26, fontWeight:900, color, lineHeight:1,
        }}>{activeKey === ' ' ? '␣' : activeKey}</span>
      </div>

      <Arrow/>

      {/* SHIFT */}
      {needShift && (
        <>
          <div style={card(false, { padding:'0 14px', gap:7 })}>
            <span style={{ fontSize:18, fontWeight:900, color:FINGER_COLORS[shiftFc], fontFamily:'monospace', lineHeight:1 }}>⇧</span>
            <div style={{ display:'flex', flexDirection:'column', gap:1 }}>
              <span style={{ fontSize:11, fontWeight:800, color:FINGER_COLORS[shiftFc], whiteSpace:'nowrap', lineHeight:1 }}>Shift</span>
              <span style={{ fontSize:10, fontWeight:600, color:FINGER_COLORS[shiftFc] + 'aa', whiteSpace:'nowrap', lineHeight:1 }}>{shiftFn?.en}</span>
            </div>
          </div>
          <Arrow/>
        </>
      )}

      {/* KEY */}
      <div style={card(true, { padding:'0 16px' })}>
        <span style={{ fontSize:22, fontWeight:900, color, fontFamily:'monospace', lineHeight:1 }}>
          {(physKey || 'SPC').toUpperCase()}
        </span>
      </div>

      <Arrow/>

      {/* FINGER */}
      <div style={card(false, {
        padding:'0 14px', flexDirection:'column',
        alignItems:'flex-start', justifyContent:'center', gap:3,
      })}>
        <div style={{ display:'flex', alignItems:'center', gap:6 }}>
          <div style={{ width:7, height:7, borderRadius:'50%', background:color, flexShrink:0, boxShadow:`0 0 5px ${color}99` }}/>
          <span style={{ fontSize:12, fontWeight:700, color:'#334155', whiteSpace:'nowrap' }}>{fn.en}</span>
        </div>
        <span style={{ fontSize:12, color:'#64748b', lineHeight:1, fontFamily:"'Raavi',sans-serif", whiteSpace:'nowrap', paddingLeft:13 }}>
          {fn.pu}
        </span>
      </div>

    </div>
  );
}

// ── Main Component ────────────────────────────────────────────────────────────
const VirtualKeyboard = ({ activeKey, isCorrect }) => {
  const lastKeyRef     = useRef(null);
  const lastCorrectRef = useRef(null);

  const { language } = useLanguage();
  const { layout: keyboardLayout, fingerMap } = getKeyboardConfig(language);

  // ── Sound ─────────────────────────────────────────────────────────────────
  useEffect(() => {
    if (isCorrect === null || isCorrect === undefined) return;
    if (lastKeyRef.current === activeKey && lastCorrectRef.current === isCorrect) return;
    lastKeyRef.current     = activeKey;
    lastCorrectRef.current = isCorrect;
    isCorrect ? playTick() : playTock();
  }, [isCorrect, activeKey]);

  const playTick = () => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator(), gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(900, ctx.currentTime);
      gain.gain.setValueAtTime(0.07, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.035);
      osc.start(ctx.currentTime); osc.stop(ctx.currentTime + 0.035);
      osc.onended = () => ctx.close();
    } catch (e) {}
  };

  const playTock = () => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator(), gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = 'sine';
      osc.frequency.setValueAtTime(280, ctx.currentTime);
      gain.gain.setValueAtTime(0.06, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.055);
      osc.start(ctx.currentTime); osc.stop(ctx.currentTime + 0.055);
      osc.onended = () => ctx.close();
    } catch (e) {}
  };

  // ── Normalize entry ───────────────────────────────────────────────────────
  const normalize = (entry) => {
    if (typeof entry === 'string') return { id:entry, label:entry, shiftLabel:null, wide:false };
    return { id:entry.key||'', label:entry.display||entry.key||'', shiftLabel:entry.shift||null, wide:entry.wide||false };
  };

  // ── Reverse map ───────────────────────────────────────────────────────────
  const reverseMap = useMemo(() => {
    const map = {};
    keyboardLayout.forEach(row => row.forEach(entry => {
      if (typeof entry === 'object' && entry.key) {
        if (entry.display) map[entry.display] = entry.key;
        if (entry.shift)   map[entry.shift]   = entry.key;
      }
    }));
    return map;
  }, [keyboardLayout]);

  const resolvePhysKey = (char) => {
    if (!char) return '';
    if (reverseMap[char]) return reverseMap[char];
    if (char === ' ') return ' ';
    return char.toLowerCase();
  };

  const fingerFor = (id) =>
    fingerMap[id] || fingerMap[id?.toLowerCase()] || ENGLISH_FM[id] || ENGLISH_FM[id?.toLowerCase()] || '';

  // ── Active key analysis ───────────────────────────────────────────────────
  const physKey      = resolvePhysKey(activeKey);
  const charFc       = fingerFor(physKey);
  const plainDisplay = (() => {
    for (const row of keyboardLayout)
      for (const entry of row)
        if (typeof entry === 'object' && entry.key === physKey) return entry.display || '';
    return physKey;
  })();
  const needShift  = !!activeKey && activeKey !== ' ' && activeKey !== plainDisplay
                     && !!reverseMap[activeKey]
                     && keyboardLayout.flat().some(e => typeof e === 'object' && e.shift === activeKey);
  const shiftFc    = needShift ? getShiftFc(charFc)  : null;
  const shiftKey   = needShift ? getShiftKey(charFc)  : null;

  const leftActive  = [charFc, shiftFc].filter(fc => fc?.startsWith('l'));
  const rightActive = [charFc, shiftFc].filter(fc => fc?.startsWith('r'));
  if (charFc === 'th' || shiftFc === 'th') { leftActive.push('th'); rightActive.push('th'); }

  const isKeyActive = (entry) => {
    if (!activeKey) return false;
    const { id, label, shiftLabel } = normalize(entry);
    if (id === 'SPACE' || id === ' ') return activeKey === ' ';
    if (label === activeKey || shiftLabel === activeKey) return true;
    if (typeof id === 'string' && id.toLowerCase() === activeKey.toLowerCase?.()) return true;
    return false;
  };

  const isShiftKeyActive = (id) => needShift && id === shiftKey;

  const getLabel = (entry) => {
    const { id, label } = normalize(entry);
    return SPEC_LABELS[id] ?? label;
  };

  return (
    <div style={{
      background: '#f8fafc',
      borderRadius: 16,
      padding: '12px 10px 10px',
      border: '1px solid #e2e8f0',
      boxShadow: '0 4px 24px rgba(0,0,0,0.06)',
      fontFamily: "'Segoe UI', sans-serif",
      userSelect: 'none',
      width: 'fit-content',
      margin: '0 auto',
    }}>

      {/* ── Guidance row: hands sit RIGHT NEXT to the suggestion cards ── */}
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',   /* whole row centred in keyboard */
        marginBottom: 10,
        gap: 8,
      }}>
        <MiniHand side="left"  activeFingers={leftActive}/>
        <SuggestionBox
          activeKey={activeKey}
          physKey={physKey}
          charFc={charFc}
          needShift={needShift}
        />
        <MiniHand side="right" activeFingers={rightActive}/>
      </div>

      {/* ── Key rows ── */}
      {keyboardLayout.map((row, ri) => (
        <div key={ri} style={{ display:'flex', gap:GAP, marginBottom:GAP, justifyContent:'center' }}>
          {row.map((entry, ki) => {
            const { id, shiftLabel, wide } = normalize(entry);
            const fk      = fingerFor(id) || 'th';
            const col     = FINGER_COLORS[fk] || '#94a3b8';
            const isMain  = isKeyActive(entry);
            const isSh    = isShiftKeyActive(id);
            const isAct   = isMain || isSh;
            const actCol  = isSh && !isMain ? FINGER_COLORS[shiftFc] || col : col;
            const spec    = !!WIDES[id];
            const w       = kw(id, wide);
            const engLabel = (!spec && id.length === 1) ? id.toUpperCase() : null;

            return (
              <div key={`${ri}-${ki}`} style={{
                width: w, height: UNIT, borderRadius: 7,
                background: isAct ? actCol : '#fff',
                border: `1.5px solid ${isAct ? actCol : '#e2e8f0'}`,
                boxShadow: isAct ? `0 3px 12px ${actCol}55` : '0 1px 3px rgba(0,0,0,0.05)',
                position: 'relative', transition: 'all 0.07s',
                transform: isAct ? 'translateY(1px)' : 'none',
                cursor: 'default', overflow: 'hidden',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
              }}>
                {!spec && (
                  <>
                    {shiftLabel && (
                      <span style={{
                        position:'absolute', top:2, left:4,
                        fontSize:13, lineHeight:1, fontWeight:800,
                        color: isAct ? 'rgba(255,255,255,0.8)' : '#94a3b8',
                        fontFamily:"'Raavi','Noto Sans Gurmukhi',sans-serif",
                      }}>{shiftLabel}</span>
                    )}
                    {engLabel && (
                      <span style={{
                        position:'absolute', top:2, right:3,
                        fontSize:10, lineHeight:1, fontWeight:900,
                        color: isAct ? 'rgba(255,255,255,0.55)' : `${col}cc`,
                        fontFamily:'monospace',
                      }}>{engLabel}</span>
                    )}
                  </>
                )}
                <span style={{
                  position:'absolute',
                  bottom: spec ? 'auto' : 3,
                  left:0, right:0, textAlign:'center',
                  fontSize: spec ? 11 : 18, lineHeight:1, fontWeight:800,
                  color: isAct ? '#fff' : '#1e293b',
                  fontFamily:"'Raavi','Noto Sans Gurmukhi',sans-serif",
                }}>{getLabel(entry)}</span>
              </div>
            );
          })}
        </div>
      ))}

      <div style={{ textAlign:'center', marginTop:5, fontSize:9, color:'#94a3b8', letterSpacing:2 }}>
        {language === 'punjabi'
          ? 'HOME ROW · ੋ ੇ ੍ ਿ ੁ  |  ਪ ਰ ਕ ਤ ਚ'
          : 'HOME ROW · A S D F  |  J K L ;'}
      </div>
    </div>
  );
};

export default VirtualKeyboard;
